            {
                id = "wary", speaker = "The Two Who Are One",
                text = "*(The body tenses, both voices retreating into a guarded unison.)* *(both, carefully:)* You're doing the *thing.* The *kind* voice. The *\"let me understand you\"* voice that *always*, *always* turns into *\"and now let me suggest a cure.\"* *(Coram:)* We've *heard* it from *priests*, *healers*, *well-meaning* fools — *(Sera:)* — every one of them *certain* that *one body, two souls* is a *problem* to be *solved.* *(both:)* So forgive us if we *flinch* from being *understood.* Understanding, in our experience, is the *first step* toward someone *deciding which of us to remove.* *(the face closes.)* We're *fine.* We're a *we*, and the *we* is *happy*, and we'd thank you to take your *insight* elsewhere before it *sharpens* into a *scalpel.* *(and they turn the single body away, two souls guarding the third one they've become.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Two Who Are One",
                text = "*(The two who are one move off through the blue-veined day — a cooper and a midwife welded by the fire into a third person neither was alone — and you carry away the most unexpected grace of the Spellplague: that the same catastrophe that *severs* a world from itself can also *fuse* two strangers into a love so complete that each would die for the other, and that the cruelest thing you could offer them is the *cure* that would make them *whole*, and *singular*, and *alone.*)*",
            });

            NpcPlagueTwainDialogue = g;
        }

        private void BuildNpcPlagueGardenerDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.plague.gardener";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "The Blue-Fire Gardener",
                text = "*(In a walled garden where the soil itself flickers with cold blue flame, an old gardener moves among impossible flora — blossoms of frozen fire, vines that grow downward, a tree whose fruit is the same fruit, endlessly, never ripening, never falling. He tends them with infinite patience and a sorrow you cannot yet place. He does not seem surprised by you; little surprises a man who gardens in plague-fire.)* Mind the threshold. *(gently.)* The garden doesn't *burn* the living — it only burns the *rules.* *(he snips at a vine that does not bleed.)* You've the look of someone walking toward something *vast.* They all come through here, eventually, the ones walking toward *vast* things. The garden is *on the way.* *(he straightens.)* Stay a moment. Let me show you what *grows*, where the fire fell. It will *matter*, later. More than you'd think.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.gardener_met", op = FlagOp.SetTrue }, new FlagClause { key = "act4.deathless_garden_seeded", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Blue-Fire Gardener",
                text = "*(He walks you among the impossible beds, and his voice carries the weight of a man who has understood something terrible and beautiful and is choosing his words with care.)* When the Spellplague came, it *killed* the natural law in this place. *Death* included. *(he gestures at the endless, unfalling fruit.)* These plants *cannot die.* Cut them — they do not bleed. Burn them — the fire is already *in* them. Deny them *water*, *sun*, *soil* — they do not *care*; they have stepped *outside* the bargain that *makes* a thing *mortal.* *(he touches a frozen blossom.)* When I *found* this garden, I *wept* with *joy.* A *deathless* garden! Flowers that would *never* wilt, fruit that would *never* rot, a green thing that would *outlast* the *sun!* I thought I had found *paradise.* *(his face clouds.)* And then I lived here. And I *watched* them. And I learned the thing this garden exists to *teach*, the thing you must *carry* toward your *vast* errand. *(quietly.)* The fruit that *cannot fall* — *also cannot ripen.* The flower that *cannot wilt* — *also cannot bloom*; it is *frozen* at the *bud.* The vine that *cannot die* — *cannot grow*, either; it is *fixed*, *exactly*, *forever.* *(he meets your eyes.)* *Deathlessness is not* eternal life, *stranger. It is* eternal pause. *To be unable to die is to be unable to* change *— to* complete *— to* become. *(softly.)* This garden does not *defy* death. It is a place where *nothing is allowed to finish.* And I have come to understand that there is no *crueler* fate — not even the Wall — than a thing that *cannot end.*",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 18] \"You're not describing a garden. You're describing the *Wall*, from the other side. The Wall *keeps* souls so they can't *dissolve* — this garden *keeps* flowers so they can't *fall* — and both call it *preservation*, and both are the same crime: *refusing a thing its ending.*\"", nextNodeId = "wall", checkAbility = Ability.Wisdom, checkDC = 18, failNodeId = "tend" },
                    new DialogueChoice { text = "\"Then the answer to the Wall was never to *preserve the faithless better.* It's to give them what this garden can't: *an ending.* A real one. The mercy isn't keeping them deathless. It's letting them *fall, ripen, finish, go.*\"", nextNodeId = "ending" },
                    new DialogueChoice { text = "\"You said this would matter later. You're not a gardener — you're a *teacher*, planted on the road on purpose, so the one walking toward the crown learns the lesson *before* they reach it. Who *set* you here? And what do you want me to do with this?\"", nextNodeId = "teacher", effects = new[] { new FlagClause { key = "act4.gardener_warning", op = FlagOp.SetTrue } } },
                    new DialogueChoice { text = "\"Is there *anything* in this garden that can still die? One plant, one corner, where finishing is still allowed? Because a gardener who grieves the deathless is keeping something *mortal* alive in secret. Show me.\"", nextNodeId = "mortal", effects = new[] { new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "wall", speaker = "The Blue-Fire Gardener",
                text = "*(He stops, and a slow, profound recognition crosses his weathered face.)* ...The Wall. From the other side. *(quietly.)* You walk toward it *knowing* it, then. Good. *(he touches the frozen blossom.)* Yes. I have *stood* in this garden for *years*, grieving flowers that *cannot bloom*, and *never once* let myself *finish* the thought you just *spoke*: that *somewhere*, there is a *garden of souls* tended the *same* way — *kept* from *dissolving*, *preserved* against their *ending*, and *called* a *mercy* by the one who *tends* it. *(his voice tightens.)* The Wall and this garden are the *same place*, stranger, built on the *same lie*: that *to keep a thing from ending is to love it.* *(he shakes his head slowly.)* But love does not *freeze* the rose at the *bud to spare it the wilting.* Love lets the rose *bloom*, and *blaze*, and *brown*, and *fall* — because the *falling* is not the *enemy* of the *blooming*. The falling is what *makes* the blooming *mean* anything. *(he looks at his deathless, frozen, paused garden with terrible tenderness.)* I cannot *free* these flowers; the fire is *in* them now, the rules are *broken* past my *mending.* But *you* — *(he grips your arm)* — *you* walk toward the *gardener of souls.* And when he offers you the *crown* — the *keeping*, the *preserving*, the *better Wall* — you will remember *my* garden, and you will *know* that the *kindest* thing you can do for a *kept* thing is not to *keep it better.* It is to *let it fall.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.gardener_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act4.deathless_is_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act3.break_the_crown_known", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "ending", speaker = "The Blue-Fire Gardener",
                text = "*(He nods slowly, and something like peace settles over his sorrow.)* Let them fall. Ripen. Finish. Go. *(softly.)* You've said it *better* than I have, in all my *years* among the frozen buds. *(he picks up a single unfallen fruit, turns it in his hand.)* The whole *world* fears *death*, stranger — builds *Walls* against it, *gardens* against it, *crowns* against it — and calls the *fearing* \"love.\" *(he sets the fruit down, where it will never rot.)* But I have *lived* with the *deathless*, and I will tell you the *secret* they *whisper*, the thing the *unfalling fruit* would *beg* you for if it had a *voice*: *\"Let me end. Please. I am so tired of being held at the bud. I want to* ripen. *I want to* fall. *I want to* feed the soil *and become* next year's tree. *Your keeping is a* cage, *and your fear of my death is a fear you have dressed as *kindness *and asked* me *to wear.\"* *(he meets your eyes, fierce and gentle.)* When you reach the Court, and the dead, and the *crown* — give them the *ending.* Not the *better keeping.* The *fall.* It is the *only* mercy that was *ever* real. *Everything* else is just a *prettier bud.* *(quietly.)* Go. And let things *finish*, stranger. The whole road has been *teaching* you *that*, if you've had the *ears.* My garden is just the *plainest* lesson.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.gardener_ending", op = FlagOp.SetTrue }, new FlagClause { key = "act4.deathless_is_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act3.break_the_crown_known", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "teacher", speaker = "The Blue-Fire Gardener",
                text = "*(He smiles — the first time — and it is sad and knowing and not at all surprised.)* You see *through* the gardener. *(he sets down his shears.)* ...I have tended this garden for a long time, stranger. *Longer* than a *mortal* span, if I'm honest, and I have *stopped* counting whether that makes me *plaguechanged*, or *placed*, or something *else.* *(quietly.)* I do not *know* who set me here. I woke in this garden one day with *shears* in my hand and a *certainty* in my chest: *that I was to tend the deathless, and learn what they teach, and tell it to the one who comes walking toward a vast and terrible choice.* *(he gestures at the frozen beds.)* Perhaps the *garden* set me. Perhaps the *fire.* Perhaps something that *loves* you, far up the road, planted a *gardener* where it knew you'd *pass*, so that you would not reach the *crown* unwarned. *(he holds your gaze.)* What do I want you to *do* with this? *(softly.)* *Carry* it. That is *all* a teacher *ever* wants. When the *Lord of the Dead* offers you his *office* — when the *crown* whispers *\"keep them, preserve them, you'll do it kinder\"* — I want you to *feel*, in your *chest*, the *frozen bud that cannot bloom*, and *understand*, *bone-deep*, that *kinder keeping is still keeping*, and that the thing the dead *need* is not a *better gardener.* *(he picks the shears back up.)* It is *the end of gardens.* Now *go.* You've the lesson. The rest of the *road* is just *practice* at *believing* it.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.gardener_teacher", op = FlagOp.SetTrue }, new FlagClause { key = "act4.gardener_warning", op = FlagOp.SetTrue }, new FlagClause { key = "act4.deathless_is_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "mortal", speaker = "The Blue-Fire Gardener",
                text = "*(He goes very still. Then, slowly, he beckons you to a far corner of the garden, shadowed, where the blue fire thins — and there, in a small bed of ordinary brown soil, a single ordinary flower grows, wilting, browning at the edges, *dying.*)* ...You found it. *(barely a whisper.)* My *secret.* *(he kneels by the mortal flower with infinite tenderness.)* I carry *ordinary* soil in, a *handful* at a time, from *beyond* the wall — soil where the *rules* still *hold* — and I keep this *one corner* where a thing is *allowed* to *die.* *(his eyes shine.)* And this *flower* — this *wilting*, *browning*, *finishing* flower — is the *most precious* thing in the *entire* garden. *Worth more* than *all* the deathless blooms *combined.* *(he touches a browning petal.)* Because it can *fall.* Because it will *feed the soil.* Because *next* spring there will be a *different* flower, a *new* one, *born* from this one's *ending* — and *that*, stranger, *that* is what the deathless can *never* have: a *future* that is *different* from the *present.* *(he looks up at you.)* The deathless are *frozen* in an *eternal now.* Only the *mortal* corner *changes.* Only where things *die* can *new* things be *born.* *(softly, fiercely.)* I tend a *whole garden* of the *undying* — and I *weep* for them, and I *love* this *one dying flower* more than *all* of them, because it is the *only* thing in here that is still *alive* in the way that *matters*: it is *going somewhere.* *Keep* that. When they offer you *deathlessness* for the *faithless* — remember the *old gardener* loved the *dying* flower *best.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.gardener_mortal", op = FlagOp.SetTrue }, new FlagClause { key = "act4.deathless_is_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.ilfaeril.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "tend", speaker = "The Blue-Fire Gardener",
                text = "*(He returns to his shears, unoffended, letting the lesson lie where it fell.)* You're not ready to *hear* it yet. *(gently.)* That's no *fault.* The garden's lesson is *heavy*, and it lands when it *lands*, not a *moment* sooner. *(he snips a vine that does not bleed.)* Walk your road. Reach your *vast* thing. And *somewhere* — perhaps with a *crown* in your hands and a *choice* in your throat — you'll *remember* an old man tending flowers that *couldn't fall*, and *then* it will *mean* something. *(he smiles faintly.)* Lessons planted in *gardens* are *patient* ones. I can *wait.* The *deathless* taught me *that*, at least. *(and he moves off among the frozen, unfalling blossoms, tending a paradise he has learned to grieve.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Blue-Fire Gardener",
                text = "*(The old gardener moves among his deathless flowers — blossoms frozen at the bud, fruit that cannot fall, a paradise where nothing is allowed to finish — and you carry away from his blue-fire garden the lesson the whole road has been circling toward: that to keep a thing from ending is not to love it but to *cage* it, that the Wall and the deathless garden are the same crime, and that the only real mercy for the kept and the preserved and the held-at-the-bud is the one thing the crown will beg you not to give them — *an ending.*)*",
            });

            NpcPlagueGardenerDialogue = g;
        }
    }
}
